function buscarUsuario() {
  return Promise.resolve({ id: 1, nome: "Ana" });
}

buscarUsuario().then(function (usuario) {
  if (usuario.nome !== "Ana") {
    throw new Error("Esperava nome Ana.");
  }
});

function buscarUsuario() {
  return Promise.resolve({ id: 1, nome: "Ana" });
}

async function testarUsuario() {
  const usuario = await buscarUsuario();

  if (usuario.nome !== "Ana") {
    throw new Error("Esperava nome Ana.");
  }
}
